const group = new THREE.Group();
const silver = new THREE.MeshLambertMaterial({ color: '#9CA3AF' });

const shaftR  = 3    * mm;
const shaftL  = 75   * mm;
const headR   = 6.25 * mm;
const headH   = 5    * mm;
const nutR    = 6.25 * mm;
const nutH    = 12   * mm;

// Bolt shaft along +X, from x=0 to x=shaftL
const shaftGeo = new THREE.CylinderGeometry(shaftR, shaftR, shaftL, 16);
shaftGeo.applyMatrix4(new THREE.Matrix4().makeRotationZ(Math.PI / 2));
shaftGeo.translate(shaftL / 2, 0, 0);
group.add(new THREE.Mesh(shaftGeo, silver));

// Hex head at x=-headH..0
const headGeo = new THREE.CylinderGeometry(headR, headR, headH, 6);
headGeo.applyMatrix4(new THREE.Matrix4().makeRotationZ(Math.PI / 2));
headGeo.translate(-headH / 2, 0, 0);
group.add(new THREE.Mesh(headGeo, silver));

// Hex nut at far end x=shaftL-nutH..shaftL
const nutGeo = new THREE.CylinderGeometry(nutR, nutR, nutH, 6);
nutGeo.applyMatrix4(new THREE.Matrix4().makeRotationZ(Math.PI / 2));
nutGeo.translate(shaftL - nutH / 2, 0, 0);
group.add(new THREE.Mesh(nutGeo, silver));

return group;
